{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This is the classical textbook example of the Ritter reaction, featuring the reaction of tert-butanol with acetonitrile in the presence of a strong acid (sulfuric acid). The tert-butanol serves as a stable precursor to the tert-butyl carbocation, which is then trapped by the nitrile. Subsequent hydrolysis of the resulting nitrilium ion intermediate yields N-tert-butylacetamide. All components are simple, acyclic, and clearly illustrate the core transformation of the Ritter reaction: carbocation + nitrile -> N-substituted amide.",
    "collision_avoidance_note": "This example uses simple, acyclic, saturated aliphatic substrates (tert-butanol and acetonitrile) to avoid overlap with other named reactions. It avoids arenes (Friedel-Crafts), alkenes (Markovnikov addition, Prins), or other functional groups that could trigger unrelated reaction family classifications. The core transformation is clearly the formation of an amide from a carbocation precursor and a nitrile, which is the defining feature of the Ritter reaction."
  }
}
